import functools

def log_calls(fn):
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        print(f"calling {fn.__name__}({args}, {kwargs})")
        result = fn(*args, **kwargs)
        print(f"{fn.__name__} -> {result}")
        return result
    return wrapper

@log_calls
def add(a, b):
    return a + b

add(2, 3)
